const DANGEROUS_PATTERNS = [
  /Runtime/i,
  /ProcessBuilder/i,
  /exec\s*\(/i,
  /getClass/i,
  /forName/i,
  /System\./i,
  /Thread/i,
  /java\./i,
  /javax\./i,
  /reflect/i,
  /import\s/i,
  /File/i,
  /Socket/i,
  /URL\(/i,
  /HttpURLConnection/i,
  /ScriptEngine/i,
  /GroovyShell/i,
  /delete/i,
  /update/i,
  /index\s*\(/i,
];

function validateScript(script) {
  if (!script || typeof script !== 'string') {
    return { valid: false, reason: 'Script must be a non-empty string' };
  }

  if (script.length > 1000) {
    return { valid: false, reason: 'Script exceeds maximum length of 1000 characters' };
  }

  for (const pattern of DANGEROUS_PATTERNS) {
    if (pattern.test(script)) {
      return { valid: false, reason: `Script contains disallowed pattern: ${pattern}` };
    }
  }

  return { valid: true };
}

