// Build filter clause from user-provided filters
function buildFilterClause(filter) {
  switch (filter.type) {
    case 'term':
      return { term: { [filter.field]: filter.value } };
    case 'terms':
      return { terms: { [filter.field]: filter.value } };
    case 'range':
      return { range: { [filter.field]: filter.value } };
    case 'exists':
      return { exists: { field: filter.field } };
    case 'bool':
      return { bool: filter.config };
    case 'geo_distance':
      return {
        geo_distance: {
          distance: filter.config.distance,
          [filter.field]: filter.value,
        },
      };
    case 'nested':
      return {
        nested: {
          path: filter.config.path,
          query: filter.config.query,
        },
      };
    default:
      throw new Error(`Unsupported filter type: ${filter.type}`);
  }
}

// Build aggregation clause
function buildAggregation(name, aggDef) {
  const agg = {};

  const aggBody = {};
  if (aggDef.field) {
    aggBody.field = aggDef.field;
  }
  if (aggDef.config) {
    Object.assign(aggBody, aggDef.config);
  }

  agg[aggDef.type] = aggBody;

  if (aggDef.sub_aggregations) {
    agg.aggs = {};
    for (const [subName, subDef] of Object.entries(aggDef.sub_aggregations)) {
      agg.aggs[subName] = buildAggregation(subName, subDef);
    }
  }

  return agg;
}

// Build the primary query from user parameters
function buildPrimaryQuery(queryParams) {
  const queryTypes = Object.keys(queryParams);

  if (queryTypes.length === 1) {
    const type = queryTypes[0];
    return { [type]: queryParams[type] };
  }

  // Multiple query types: wrap in bool.must
  const mustClauses = [];
  for (const [type, value] of Object.entries(queryParams)) {
    mustClauses.push({ [type]: value });
  }
  return { bool: { must: mustClauses } };
}

// Build complete Elasticsearch Query DSL
function buildQueryDSL(params) {
  const body = {};
  let primaryQuery = buildPrimaryQuery(params.query);

  // Apply filters
  if (params.filters && params.filters.length > 0) {
    const filterClauses = params.filters.map(buildFilterClause);

    if (primaryQuery.bool) {
      primaryQuery.bool.filter = [
        ...(primaryQuery.bool.filter ? (Array.isArray(primaryQuery.bool.filter) ? primaryQuery.bool.filter : [primaryQuery.bool.filter]) : []),
        ...filterClauses,
      ];
    } else {
      primaryQuery = {
        bool: {
          must: [primaryQuery],
          filter: filterClauses,
        },
      };
    }
  }

  // Apply custom scoring
  if (params.scoring) {
    body.query = {
      script_score: {
        query: primaryQuery,
        script: {
          lang: params.scoring.lang || 'painless',
          source: params.scoring.script,
          params: params.scoring.params || {},
        },
        max_boost: params.scoring.max_boost || 100,
      },
    };

    if (params.scoring.boost_mode) {
      body.query.script_score.boost_mode = params.scoring.boost_mode;
    }

    if (params.scoring.min_score !== undefined) {
      body.min_score = params.scoring.min_score;
    }
  } else {
    body.query = primaryQuery;
  }

  // Pagination
  body.from = params.from;
  body.size = params.size;

  // Source filtering
  if (params._source !== undefined) {
    body._source = params._source;
  }

  // Sorting
  if (params.sort) {
    body.sort = params.sort;
  }

  // Highlighting
  if (params.highlight) {
    body.highlight = params.highlight;
  }

  // Aggregations
  if (params.aggregations) {
    body.aggs = {};
    for (const [name, aggDef] of Object.entries(params.aggregations)) {
      body.aggs[name] = buildAggregation(name, aggDef);
    }
  }

  // Suggestions
  if (params.suggest) {
    body.suggest = params.suggest;
  }

  // Field collapsing
  if (params.collapse) {
    body.collapse = params.collapse;
  }

  // Track total hits
  body.track_total_hits = params.track_total_hits;

  // Search after (for deep pagination)
  if (params.search_after) {
    body.search_after = params.search_after;
  }

  // Point in time
  if (params.pit) {
    body.pit = params.pit;
  }

  return body;
}

// Main search endpoint
app.post('/api/search', async (req, res) => {
  try {
    // Validate input
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path,
        })),
      });
    }

    // Validate custom scoring script if provided
    if (params.scoring) {
      const scriptValidation = validateScript(params.scoring.script);
      if (!scriptValidation.valid) {
        return res.status(400).json({
          error: 'Script validation failed',
          reason: scriptValidation.reason,
        });
      }
    }

    // Build query DSL
    const queryDSL = buildQueryDSL(params);

    console.log('Executing query:', JSON.stringify(queryDSL, null, 2));

    // Execute search
    const searchParams = {
      body: queryDSL,
    };

    if (!params.pit) {
      searchParams.index = params.index;
    }

    const result = await esClient.search(searchParams);

    // Format response
    const response = {
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
        inner_hits: hit.inner_hits || undefined,
      })),
      took: result.took,
      timed_out: result.timed_out,
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    if (result.suggest) {
      response.suggest = result.suggest;
    }

    if (result.pit_id) {
      response.pit_id = result.pit_id;
    }

    res.json(response);
  } catch (err) {
    console.error('Search error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

