// Get a specific scoring template
app.get('/api/search/scoring-templates/:name', (req, res) => {
  const template = SCORING_TEMPLATES[req.params.name];
  if (!template) {
    return res.status(404).json({ error: 'Scoring template not found' });
  }
  res.json({ name: req.params.name, ...template });
});

// Search using a scoring template
app.post('/api/search/with-template', async (req, res) => {
  try {
    const { template_name, template_params, ...searchParams } = req.body;

    if (!template_name) {
      return res.status(400).json({ error: 'template_name is required' });
    }

    const template = SCORING_TEMPLATES[template_name];
    if (!template) {
      return res.status(404).json({ error: `Scoring template '${template_name}' not found` });
    }

    // Merge default params with user-provided params
    const mergedParams = {
      ...template.default_params,
      ...(template_params || {}),
    };

    // Build the search params with the template scoring
    const fullSearchParams = {
      ...searchParams,
      scoring: {
        script: template.script,
        lang: 'painless',
        params: mergedParams,
      },
    };

    const { error, value: params } = searchParamsSchema.validate(fullSearchParams, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path,
        })),
      });
    }

    const queryDSL = buildQueryDSL(params);

    console.log('Executing template query:', JSON.stringify(queryDSL, null, 2));

    const result = await esClient.search({
      index: params.index,
      body: queryDSL,
    });

    const response = {
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        _index: hit._index,
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
      })),
      took: result.took,
      timed_out: result.timed_out,
      template_used: template_name,
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    res.json(response);
  } catch (err) {
    console.error('Template search error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

