app.post('/api/search/multi', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!Array.isArray(searches) || searches.length === 0) {
      return res.status(400).json({ error: 'searches must be a non-empty array' });
    }

    if (searches.length > 20) {
      return res.status(400).json({ error: 'Maximum 20 searches allowed per batch' });
    }

    const msearchBody = [];

    for (const search of searches) {
      const { error, value: params } = searchParamsSchema.validate(search, {
        abortEarly: false,
        stripUnknown: true,
      });

      if (error) {
        return res.status(400).json({
          error: 'Validation error in batch search',
          details: error.details.map(d => ({
            message: d.message,
            path: d.path,
          })),
        });
      }

      if (params.scoring) {
        const scriptValidation = validateScript(params.scoring.script);
        if (!scriptValidation.valid) {
          return res.status(400).json({
            error: 'Script validation failed',
            reason: scriptValidation.reason,
          });
        }
      }

      const queryDSL = buildQueryDSL(params);

      msearchBody.push({ index: params.index });
      msearchBody.push(queryDSL);
    }

    const result = await esClient.msearch({ body: msearchBody });

    const responses = result.responses.map((r, i) => {
      if (r.error) {
        return { error: r.error, status: r.status };
      }
      return {
        total: r.hits.total,
        max_score: r.hits.max_score,
        hits: r.hits.hits.map(hit => ({
          _index: hit._index,
          _id: hit._id,
          _score: hit._score,
          _source: hit._source,
          highlight: hit.highlight || undefined,
        })),
        took: r.took,
        aggregations: r.aggregations || undefined,
      };
    });

    res.json({ responses, took: result.took });
  } catch (err) {
    console.error('Multi-search error:', err);
    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Explain endpoint - explains scoring for a specific document
app.post('/api/search/explain/:index/:id', async (req, res) => {
  try {
    const { error, value: params } = searchParamsSchema.validate(
      { ...req.body, index: req.params.index },
      { abortEarly: false, stripUnknown: true }
    );

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path,
        })),
      });
    }

    if (params.scoring) {
      const scriptValidation = validateScript(params.scoring.script);
      if (!scriptValidation.valid) {
        return res.status(400).json({
          error: 'Script validation failed',
          reason: scriptValidation.reason,
        });
      }
    }

    const queryDSL = buildQueryDSL(params);

    const result = await esClient.explain({
      index: req.params.index,
      id: req.params.id,
      body: { query: queryDSL.query },
    });

    res.json({
      matched: result.matched,
      explanation: result.explanation,
    });
  } catch (err) {
    console.error('Explain error:', err);

    if (err.meta && err.meta.body) {
      return res.status(err.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: err.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Open a Point in Time for deep pagination
app.post('/api/search/pit/open', async (req, res) => {
  try {
    const { index, keep_alive } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'index is required' });
    }

    const result = await esClient.openPointInTime({
      index,
      keep_alive: keep_alive || '5m',
    });

    res.json({ pit_id: result.id });
  } catch (err) {
    console.error('PIT open error:', err);
    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Close a Point in Time
app.post('/api/search/pit/close', async (req, res) => {
  try {
    const { pit_id } = req.body;

    if (!pit_id) {
      return res.status(400).json({ error: 'pit_id is required' });
    }

    const result = await esClient.closePointInTime({
      body: { id: pit_id },
    });

    res.json({ succeeded: result.succeeded });
  } catch (err) {
    console.error('PIT close error:', err);
    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Health check endpoint
app.get('/api/health', async (req, res) => {
  try {
    const health = await esClient.cluster.health();
    res.json({
      status: 'ok',
      elasticsearch: {
        cluster_name: health.cluster_name,
        status: health.status,
        number_of_nodes: health.number_of_nodes,
        active_shards: health.active_shards,
      },
    });
  } catch (err) {
    res.status(503).json({
      status: 'error',
      message: 'Cannot connect to Elasticsearch',
      error: err.message,
    });
  }
});

// Get index mappings
app.get('/api/indices/:index/mappings', async (req, res) => {
  try {
    const result = await esClient.indices.getMapping({
      index: req.params.index,
    });
    res.json(result);
  } catch (err) {
    console.error('Mapping error:', err);
    if (err.meta && err.meta.statusCode === 404) {
      return res.status(404).json({ error: 'Index not found' });
    }
    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? err.message : 'An unexpected error occurred',
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Enterprise Search Platform running on port ${PORT}`);
  console.log(`Elasticsearch node: ${process.env.ELASTICSEARCH_URL || 'http://localhost:9200'}`);
});

module.exports = { app, buildQueryDSL, buildPrimaryQuery, buildFilterClause, validateScript, SCORING_TEMPLATES };